parameters.jsCode:
const data = $input.first().json;
const appointmentText = data.appointment_time || '';

// Часовой пояс Екатеринбурга (UTC+5)
const TIMEZONE_OFFSET_HOURS = 5;

function parseDate(text) {
  // ISO формат (2026-01-28 13:00)
  const isoMatch = text.match(/(\d{4})-(\d{2})-(\d{2})[T\s](\d{1,2}):(\d{2})/);
  if (isoMatch) {
    const [_, year, month, day, hours, minutes] = isoMatch;
    const localDate = new Date(Date.UTC(
      parseInt(year), 
      parseInt(month) - 1, 
      parseInt(day), 
      parseInt(hours) - TIMEZONE_OFFSET_HOURS, 
      parseInt(minutes)
    ));
    return localDate;
  }

  // Русский текст
  const now = new Date();
  const localNow = new Date(now.getTime() + TIMEZONE_OFFSET_HOURS * 60 * 60 * 1000);
  let targetDate = new Date(localNow);
  const lowerText = text.toLowerCase();

  if (lowerText.includes('завтра')) {
    targetDate.setUTCDate(targetDate.getUTCDate() + 1);
  } else if (lowerText.includes('послезавтра')) {
    targetDate.setUTCDate(targetDate.getUTCDate() + 2);
  }

  const timeMatch = text.match(/(\d{1,2})[:\s-]?(\d{2})?/);
  if (timeMatch) {
    const hours = parseInt(timeMatch[1]);
    const minutes = timeMatch[2] ? parseInt(timeMatch[2]) : 0;
    targetDate.setUTCHours(hours - TIMEZONE_OFFSET_HOURS, minutes, 0, 0);
  } else {
    if (lowerText.includes('утр')) targetDate.setUTCHours(9 - TIMEZONE_OFFSET_HOURS, 0, 0, 0);
    else if (lowerText.includes('вечер')) targetDate.setUTCHours(18 - TIMEZONE_OFFSET_HOURS, 0, 0, 0);
    else targetDate.setUTCHours(12 - TIMEZONE_OFFSET_HOURS, 0, 0, 0);
  }

  return targetDate;
}

const appointmentDate = parseDate(appointmentText);
const appointmentTimestamp = Math.floor(appointmentDate.getTime() / 1000);
const reminderTimestamp = appointmentTimestamp - 3600;

const displayDate = new Date(appointmentDate.getTime() + TIMEZONE_OFFSET_HOURS * 60 * 60 * 1000);
const timeFormatted = displayDate.getUTCHours().toString().padStart(2, '0') + ':' + displayDate.getUTCMinutes().toString().padStart(2, '0');

// Новый формат: Пациент — причина
const deal_name = `${data.patient_name} \u2014 ${data.complaint}`;

// Формат для AmoCRM и Google Calendar (Y-m-d\TH:i:sP) с часовым поясом
const pad = (n) => n.toString().padStart(2, '0');
const y = displayDate.getUTCFullYear();
const m = pad(displayDate.getUTCMonth() + 1);
const d = pad(displayDate.getUTCDate());
const h = pad(displayDate.getUTCHours());
const min = pad(displayDate.getUTCMinutes());
const s = pad(displayDate.getUTCSeconds());

// Единый формат с явным указанием часового пояса Екатеринбурга
const date_iso = `${y}-${m}-${d}T${h}:${min}:${s}+05:00`;
const appointment_iso = date_iso; // Теперь одинаковый формат для всех

return [{
  json: {
    ...data,
    appointment_timestamp: appointmentTimestamp,
    reminder_timestamp: reminderTimestamp,
    time_formatted: timeFormatted,
    deal_name: deal_name,
    appointment_iso: appointment_iso,
    date_iso: date_iso
  }
}];

